script.text:

function loading$PITrainingCourses(f) {f.add_onResponseComplete(on$PITrainingCourses$ResponseComplete);}
function closing$PITrainingCourses(f) {try {f.remove_onResponseComplete(on$PITrainingCourses$ResponseComplete);} catch (ex) {}}
function on$PITrainingCourses$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
		case 'Course':
		  f.setItemValues('ma_mh, ten_mh%l, loai_hinh_dt, ten_loai%l, ma_dvdt, ten_dvdt%l, ngay_hoc1, ngay_hoc2, so_gio',
		    [result[0].Value, result[1].Value, result[2].Value, result[3].Value, result[4].Value, result[5].Value, result[6].Value, result[7].Value, result[8].Value]);
      break;
    default:
      break;
  }
}
function onChange$TrainCourseInfor(o) {o.parentForm.request('Course', 'Course', ['ma_khoa']);}
